/// BTLoadingSkeleton — INTERNAL shimmer skeleton utility.
///
/// This class is NOT part of the btech_ui public API.
/// Do NOT import it from application code.
///
/// Public API: use [BTLoading.skeleton] and [BTLoading.skeletonLeaf] instead.
///
/// Kept as an internal helper for components (e.g. [BTAvatar]) that need
/// to apply Skeletonizer directly to a child tree without going through
/// the [BTLoading] dispatcher.
///
/// [skeletonizer] is pinned at `1.4.3` in pubspec.yaml — bump manually
/// after regression-testing (no silent breaking changes).
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';
import 'package:skeletonizer/skeletonizer.dart';

/// Skeleton type — selects which Skeletonizer variant to render.
enum _BTSkeletonType { base, leaf }

/// BTLoadingSkeleton — see file header for usage.
class BTLoadingSkeleton extends StatelessWidget {
  /// Wraps [child] in a [Skeletonizer] that shimmers the entire subtree.
  const BTLoadingSkeleton({
    required this.child,
    this.enabled = true,
    this.ignoreContainers = false,
    super.key,
  }) : _type = _BTSkeletonType.base;

  /// Marks [child] as a single [Skeleton.leaf] node inside a parent
  /// [Skeletonizer]. [ignoreContainers] has no effect for this variant.
  const BTLoadingSkeleton.leaf({
    required this.child,
    this.enabled = true,
    super.key,
  })  : _type = _BTSkeletonType.leaf,
        ignoreContainers = false;

  /// When `true`, the shimmer effect is active and [child] is hidden.
  /// When `false`, [child] is rendered normally.
  final bool enabled;

  /// When `true`, container decorations (backgrounds, borders) are
  /// excluded from the shimmer. Only text, icons and images shimmer.
  /// Only applies to the default [BTLoadingSkeleton] constructor.
  final bool ignoreContainers;

  /// The content to display once [enabled] is `false`.
  final Widget child;

  final _BTSkeletonType _type;

  @override
  Widget build(BuildContext context) {
    if (_type == _BTSkeletonType.leaf) {
      return Skeleton.leaf(
        enabled: enabled,
        child: child,
      );
    }

    // Use btech context tokens for shimmer colors so they stay
    // consistent with the tenant theme and light/dark mode.
    final baseColor = context.btColor.bg.subtler;
    final highlightColor = context.btColor.bg.primary;

    return Skeletonizer(
      enabled: enabled,
      ignoreContainers: ignoreContainers,
      effect: ShimmerEffect(
        baseColor: baseColor,
        highlightColor: highlightColor,
      ),
      child: child,
    );
  }
}

// Public barrel for BTLoading.
export 'loading.types.dart';
export 'loading.widget.dart';

/// BTLoading types — Figma node 3227:400.
library;

/// Selects which loading indicator [BTLoading] renders.
enum BTLoadingType {
  /// Lottie concentric-ring spinner (load-spin-anim.json / load-spin-anim-dark.json).
  spinner,

  /// Lottie 4-dot pulsing indicator (load-pulse-anim.json / load-pulse-anim-dark.json).
  pulse,

  /// Shimmer skeleton — wraps [child] (or a simple block) in Skeletonizer.
  skeleton,

  /// Skeleton leaf — marks a single widget as a [Skeleton.leaf] inside an
  /// existing [Skeletonizer]. Use via [BTLoading.skeletonLeaf].
  skeletonLeaf,

  /// Horizontal progress bar (indeterminate when no value, determinate 0–1).
  progressbar,

  /// BTech logo gradient animation (load-btech-anim.json). No color tint.
  logo,
}

/// BTLoading — multi-type loading indicator atom (Figma 3227:400).
///
/// Five named constructors map to five rendering strategies:
///
/// ```dart
/// // Lottie spinner — 48 × 48 by default
/// BTLoading.spinner()
///
/// // Lottie pulse with custom tint
/// BTLoading.pulse(color: Colors.green)
///
/// // Skeleton shimmer — simple block (width × height)
/// BTLoading.skeleton(width: 200, height: 20)
///
/// // Skeleton shimmer — wraps an arbitrary child widget tree
/// BTLoading.skeleton(
///   child: MyCard(),
///   enabled: isLoading,
///   ignoreContainers: true,
/// )
///
/// // Skeleton leaf — marks a single widget as a shimmer leaf inside an
/// // existing BTLoading.skeleton (or raw Skeletonizer) parent.
/// BTLoading.skeletonLeaf(
///   child: MyAvatarWidget(),
///   enabled: isLoading,
/// )
///
/// // Indeterminate progress bar
/// BTLoading.progressbar()
///
/// // Determinate progress bar (60% filled)
/// BTLoading.progressbar(value: 0.6)
///
/// // BTech gradient logo animation
/// BTLoading.logo()
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/loading/loading.types.dart';
import 'package:flutter/material.dart';
import 'package:lottie/lottie.dart';
import 'package:skeletonizer/skeletonizer.dart';

/// Multi-type loading indicator. See file header for all usage examples.
class BTLoading extends StatelessWidget {
  /// Lottie concentric-ring spinner.
  const BTLoading.spinner({
    Color? color,
    double size = 48,
    super.key,
  })  : _type = BTLoadingType.spinner,
        _color = color,
        _size = size,
        _value = null,
        _child = null,
        _skeletonEnabled = true,
        _skeletonIgnoreContainers = false,
        _skeletonWidth = null,
        _skeletonHeight = 40;

  /// Lottie 4-dot pulsing indicator.
  const BTLoading.pulse({
    Color? color,
    double size = 48,
    super.key,
  })  : _type = BTLoadingType.pulse,
        _color = color,
        _size = size,
        _value = null,
        _child = null,
        _skeletonEnabled = true,
        _skeletonIgnoreContainers = false,
        _skeletonWidth = null,
        _skeletonHeight = 40;

  /// Shimmer skeleton rendered via the [skeletonizer] package.
  ///
  /// **Two modes:**
  ///
  /// 1. **Child mode** — pass [child] to wrap an arbitrary widget tree in a
  ///    [Skeletonizer]. All content inside shimmers while [enabled] is `true`.
  ///    ```dart
  ///    BTLoading.skeleton(
  ///      child: MyCard(),
  ///      enabled: isLoading,
  ///      ignoreContainers: true,
  ///    )
  ///    ```
  ///
  /// 2. **Block mode** — omit [child] and pass [width]/[height] to render a
  ///    standalone shimmer rectangle (default 40 dp tall, full width).
  ///    ```dart
  ///    BTLoading.skeleton(width: 120, height: 16)
  ///    ```
  ///
  /// [enabled]            — when `false`, [child] renders normally (block mode:
  ///                        the shimmer rect disappears). Defaults to `true`.
  /// [ignoreContainers]   — when `true`, container backgrounds are excluded from
  ///                        the shimmer; only text/icons/images shimmer.
  ///                        Only meaningful in child mode.
  const BTLoading.skeleton({
    Widget? child,
    bool enabled = true,
    bool ignoreContainers = false,
    double? width,
    double height = 40,
    super.key,
  })  : _type = BTLoadingType.skeleton,
        _color = null,
        _size = 0,
        _value = null,
        _child = child,
        _skeletonEnabled = enabled,
        _skeletonIgnoreContainers = ignoreContainers,
        _skeletonWidth = width,
        _skeletonHeight = height;

  /// Marks [child] as a single [Skeleton.leaf] inside a parent
  /// [BTLoading.skeleton] (or raw [Skeletonizer]).
  ///
  /// Use this when you only want ONE specific widget inside a larger
  /// skeletonised tree to shimmer, leaving siblings unaffected.
  ///
  /// ```dart
  /// BTLoading.skeleton(
  ///   child: Row(children: [
  ///     BTLoading.skeletonLeaf(child: MyAvatar()),
  ///     const Text('Name'),  // ← also shimmers (normal Skeletonizer behavior)
  ///   ]),
  /// )
  /// ```
  const BTLoading.skeletonLeaf({
    required Widget child,
    bool enabled = true,
    super.key,
  })  : _type = BTLoadingType.skeletonLeaf,
        _color = null,
        _size = 0,
        _value = null,
        _child = child,
        _skeletonEnabled = enabled,
        _skeletonIgnoreContainers = false,
        _skeletonWidth = null,
        _skeletonHeight = 0;

  /// Horizontal progress bar.
  ///
  /// [value] null → indeterminate looping animation.
  /// [value] 0.0–1.0 → determinate fill.
  const BTLoading.progressbar({
    Color? color,
    double? value,
    super.key,
  })  : _type = BTLoadingType.progressbar,
        _color = color,
        _size = 0,
        _value = value,
        _child = null,
        _skeletonEnabled = true,
        _skeletonIgnoreContainers = false,
        _skeletonWidth = null,
        _skeletonHeight = 0;

  /// BTech gradient logo animation. No color tint.
  const BTLoading.logo({
    double size = 48,
    super.key,
  })  : _type = BTLoadingType.logo,
        _color = null,
        _size = size,
        _value = null,
        _child = null,
        _skeletonEnabled = true,
        _skeletonIgnoreContainers = false,
        _skeletonWidth = null,
        _skeletonHeight = 0;

  final BTLoadingType _type;
  final Color? _color;
  final double _size;
  final double? _value;

  // ── skeleton / skeletonLeaf ───────────────────────────────────────────────
  /// Optional child to wrap. When null, [BTLoading.skeleton] renders a block.
  final Widget? _child;

  /// Controls whether the shimmer is active (skeleton / skeletonLeaf).
  final bool _skeletonEnabled;

  /// Exclude container backgrounds from shimmer (skeleton child mode only).
  final bool _skeletonIgnoreContainers;

  /// Block-mode width for [BTLoading.skeleton] when no [_child] is provided.
  final double? _skeletonWidth;

  /// Block-mode height for [BTLoading.skeleton] when no [_child] is provided.
  final double _skeletonHeight;

  static const String _animBase = 'packages/btech_assets/assets/anim/';

  String _assetPath(Brightness brightness) => switch (_type) {
        BTLoadingType.spinner =>
          '${_animBase}${brightness == Brightness.dark ? 'load-spin-anim-dark' : 'load-spin-anim'}.json',
        BTLoadingType.pulse =>
          '${_animBase}${brightness == Brightness.dark ? 'load-pulse-anim-dark' : 'load-pulse-anim'}.json',
        BTLoadingType.logo        => '${_animBase}load-btech-anim.json',
        BTLoadingType.skeleton    => '',
        BTLoadingType.skeletonLeaf => '',
        BTLoadingType.progressbar => '',
      };

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    return switch (_type) {
      BTLoadingType.spinner ||
      BTLoadingType.pulse ||
      BTLoadingType.logo =>
        _buildLottie(context),
      BTLoadingType.skeleton     => _buildSkeleton(colors),
      BTLoadingType.skeletonLeaf => _buildSkeletonLeaf(),
      BTLoadingType.progressbar  => _buildProgressbar(colors),
    };
  }

  Widget _buildLottie(BuildContext context) {
    final Widget lottie = Lottie.asset(
      _assetPath(Theme.of(context).brightness),
      width: _size,
      height: _size,
      options: LottieOptions(enableMergePaths: true),
    );

    // Logo plays as-is (gradient). Spinner/pulse support optional tint.
    if (_type != BTLoadingType.logo && _color != null) {
      return ColorFiltered(
        colorFilter: ColorFilter.mode(_color!, BlendMode.srcIn),
        child: lottie,
      );
    }
    return lottie;
  }

  Widget _buildSkeleton(BTColorTheme colors) {
    // Block mode — no child provided: render a simple shimmer rectangle.
    final Widget effectiveChild = _child ??
        SizedBox(
          width: _skeletonWidth,
          height: _skeletonHeight,
          child: const DecoratedBox(
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.all(Radius.circular(10)),
            ),
          ),
        );

    return Skeletonizer(
      enabled: _skeletonEnabled,
      ignoreContainers: _skeletonIgnoreContainers,
      effect: ShimmerEffect(
        baseColor: colors.bg.subtler,
        highlightColor: colors.bg.primary,
      ),
      child: effectiveChild,
    );
  }

  /// Marks [_child] as a [Skeleton.leaf] inside a parent Skeletonizer.
  Widget _buildSkeletonLeaf() {
    return Skeleton.leaf(
      enabled: _skeletonEnabled,
      child: _child!,
    );
  }

  Widget _buildProgressbar(BTColorTheme colors) {
    final effectiveColor = _color ?? colors.brand.primary;
    return Container(
      clipBehavior: Clip.antiAliasWithSaveLayer,
      height: 4,
      decoration: const BoxDecoration(
        borderRadius: BorderRadius.all(Radius.circular(9999)),
      ),
      child: LinearProgressIndicator(
        value: _value,
        backgroundColor: effectiveColor.withValues(alpha: 0.10),
        valueColor: AlwaysStoppedAnimation<Color>(effectiveColor),
        minHeight: 4,
      ),
    );
  }
}
